export function BrandLogo({
  className = "",
  variant = "full",
  title = "THE ROOM — Private Hair Studio",
}: {
  className?: string;
  variant?: Variant;
  title?: string;
}) {
  if (variant === "horizontal") {
    return (
      <svg
        viewBox="0 0 400 400"
        xmlns="http://www.w3.org/2000/svg"
        role="img"
        aria-label={title}
        className={`select-none ${className}`}
        fill="none"
      >
        <title>{title}</title>
        {FRAME_PATHS}
      </svg>
    );
  }

  if (variant === "mark") {
    return (
      <svg
        viewBox="0 0 400 400"
        xmlns="http://www.w3.org/2000/svg"
        role="img"
        aria-label={title}
        className={`select-none ${className}`}
        fill="none"
      >
        <title>{title}</title>
        {FRAME_PATHS}
      </svg>
    );
  }

  // full
  return (
    <svg
      viewBox="0 0 400 470"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label={title}
      className={`select-none ${className}`}
      fill="none"
    >
      <title>{title}</title>
      {FRAME_PATHS}
      <g fill="currentColor">
        <text x="200" y="434" textAnchor="middle" fontFamily="'Josefin Sans', system-ui, sans-serif" fontWeight="300" fontSize="15" letterSpacing="6">PRIVATE HAIR STUDIO</text>
        <text x="200" y="460" textAnchor="middle" fontFamily="'Josefin Sans', system-ui, sans-serif" fontWeight="300" fontSize="10" letterSpacing="4" opacity="0.7">BY APPOINTMENT ONLY</text>
      </g>
    </svg>
  );
}